### Define Dexie.js Export/Import JSON Structure Interface

Source: https://github.com/dexie/dexie.js/blob/master/addons/dexie-export-import/README.md

Defines the TypeScript interface `DexieExportJsonStructure` which describes the expected JSON format for data exported from and imported into Dexie.js. This format is designed for streaming, with `data` and `rows` properties appearing last.

```ts
export interface DexieExportJsonStructure {
  formatName: 'dexie';
  formatVersion: 1;
  data: {
    databaseName: string;
    databaseVersion: number;
    tables: Array<{
      name: string;
      schema: string; // '++id,name,age'
      rowCount: number;
    }>;
    data: Array<{ // This property must be last (for streaming purpose)
      tableName: string;
      inbound: boolean;
      rows: any[]; // This property must be last (for streaming purpose)
    }>;
  }
}
```

