### Define Dexie.js Import Options Interfaces

Source: https://github.com/dexie/dexie.js/blob/master/addons/dexie-export-import/README.md

Defines the TypeScript interfaces for `StaticImportOptions` and `ImportOptions` used with `Dexie.import()` and `Dexie.prototype.import()`. These options control transaction behavior, chunking, filtering, progress callbacks, and handling of missing tables or schema differences during import.

```ts
export interface StaticImportOptions {
  noTransaction?: boolean;
  chunkSizeBytes?: number; // Default: DEFAULT_KILOBYTES_PER_CHUNK ( 1MB )
  filter?: (table: string, value: any, key?: any) => boolean;
  progressCallback?: (progress: ImportProgress) => boolean;
  name?: string;
}

export interface ImportOptions extends StaticImportOptions {
  acceptMissingTables?: boolean;
  acceptVersionDiff?: boolean;
  acceptNameDiff?: boolean;
  acceptChangedPrimaryKey?: boolean;
  overwriteValues?: boolean;
  clearTablesBeforeImport?: boolean;
  noTransaction?: boolean;
  chunkSizeBytes?: number; // Default: DEFAULT_KILOBYTES_PER_CHUNK ( 1MB )
  filter?: (table: string, value: any, key?: any) => boolean;
  progressCallback?: (progress: ImportProgress) => boolean;
}
```

