### Asynchronously Reading Blob Content into a String

Source: https://github.com/dexie/dexie.js/blob/master/addons/dexie-export-import/README.md

This TypeScript function provides an asynchronous way to read the content of a Blob into a string using FileReader. It returns a Promise that resolves with the text content or rejects on error or abort. This function is used in conjunction with Blob slicing for chunked reading.

```ts
const first100Chars = await readBlob(firstPart);

function readBlob(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onabort = ev => reject(new Error("file read aborted"));
    reader.onerror = ev => reject((ev.target as any).error);
    reader.onload = ev => resolve((ev.target as any).result);
    reader.readAsText(blob);
  });
}
```

